SELECT ?year WHERE {
  wd:Q1187134 wdt:P1164 ?title.
  ?title wdt:P585 ?year.
} ORDER BY DESC(?year) LIMIT 1

SELECT DISTINCT ?year WHERE {
  ?championship wdt:P1371 wd:Q10608114;
             wdt:P585 ?year;
             rdfs:label ?titleLabel.
  FILTER(LANG(?titleLabel) = "en").
  FILTER(CONTAINS(LCASE(?titleLabel), "national championship")).
} ORDER BY DESC(?year) LIMIT 1

SELECT ?year WHERE {
  ?title wdt:P1371 wd:Q10608114;
         wdt:P31 wd:Q445800;
         wdt:P585 ?year.
} ORDER BY DESC(?year) LIMIT 1

SELECT ?year WHERE {
  wd:Q10608114 p:P243 [ ps:P585 ?year ].
} ORDER BY DESC(?year) LIMIT 1

